     1|/**
     2| * IVX → Rork Independence Engine.
     3| *
     4| * The owner's objective: replace the Rork dependency with IVX AI as the primary
     5| * autonomous developer/operator, across four phases —
     6| *   1 Shadow Mode      — IVX does inspect/plan/edit/test/deploy/verify/report; Rork only audits.
     7| *   2 IVX Primary Mode — IVX executes directly; Rork is fallback only.
     8| *   3 Independence Mode— Rork removed from the normal workflow; keep only GitHub,
     9| *                        Render, Supabase, OpenAI/provider, IVX backend, IVX memory,
    10| *                        IVX scheduler, IVX action loop.
    11| *   4 Final Removal    — Rork becomes optional, not required.
    12| *
    13| * This module does NOT narrate progress — it DERIVES the live phase from real
    14| * signals: the autonomous tool-availability checker (BLOCK 35), the operator
    15| * handoff manifest (10 capabilities), and a direct scan of the Rork-specific
    16| * dependencies still present in the repo/runtime. Every phase requirement reports
    17| * met/unmet + the exact missing item; nothing is a hardcoded boolean.
    18| *
    19| * Read-only. Never mutates anything.
    20| */
    21|import { readFile } from 'node:fs/promises';
    22|import path from 'node:path';
    23|import { checkToolAvailability, type ToolAvailabilityReport } from './ivx-tool-availability';
    24|// Type-only import: the concrete builder is lazy-imported inside the assembler so
    25|// the pure logic stays loadable without the heavy AI runtime (mirrors BLOCK 37/39).
    26|import type { HandoffManifest } from './ivx-handoff';
    27|
    28|export const IVX_RORK_INDEPENDENCE_MARKER = 'ivx-rork-independence-2026-06-02';
    29|
    30|export type IndependencePhaseId = 'shadow' | 'ivx_primary' | 'independence' | 'final_removal';
    31|export type PhaseReadiness = 'achieved' | 'in_progress' | 'blocked';
    32|
    33|export type PhaseRequirement = {
    34|  label: string;
    35|  met: boolean;
    36|  detail: string;
    37|  /** Exact missing item when unmet (null when met). */
    38|  missing: string | null;
    39|};
    40|
    41|export type IndependencePhase = {
    42|  id: IndependencePhaseId;
    43|  /** 1..4 — matches the owner's phase order. */
    44|  order: number;
    45|  title: string;
    46|  objective: string;
    47|  /** Rork's role in this phase. */
    48|  rorkRole: string;
    49|  requirements: PhaseRequirement[];
    50|  readiness: PhaseReadiness;
    51|};
    52|
    53|/** One of the eight systems IVX keeps in Independence Mode. */
    54|export type KeptSystem = {
    55|  system: string;
    56|  available: boolean;
    57|  backedBy: string;
    58|  missing: string | null;
    59|};
    60|
    61|/** A Rork-specific dependency that must be gone before full independence. */
    62|export type RorkDependency = {
    63|  dependency: string;
    64|  present: boolean;
    65|  risk: 'critical' | 'high' | 'medium' | 'low';
    66|  detail: string;
    67|  removalAction: string;
    68|};
    69|
    70|/**
    71| * BLOCK 47 — the executable build-independence cutover prepared in the repo.
    72| * The cutover CANNOT run inside the Rork sandbox (the cloud bundler requires
    73| * `withRorkMetro` + `@rork-ai/toolkit-sdk` and auto-restores the SDK), so it is
    74| * shipped as a guarded, runnable artifact the owner executes on the independent
    75| * GitHub/Render checkout. This reports whether that artifact is present.
    76| */
    77|export type CutoverTooling = {
    78|  ready: boolean;
    79|  cutoverScript: string;
    80|  cutoverScriptPresent: boolean;
    81|  standaloneMetroConfig: string;
    82|  standaloneMetroConfigPresent: boolean;
    83|  ownerBuildPipeline: string;
    84|  ownerBuildPipelinePresent: boolean;
    85|  runCommand: string;
    86|  detail: string;
    87|};
    88|
    89|export type RorkIndependenceReport = {
    90|  marker: string;
    91|  generatedAt: string;
    92|  /** Highest fully-achieved phase IVX is operating at right now. */
    93|  currentPhase: IndependencePhaseId;
    94|  currentPhaseOrder: number;
    95|  /** The phase currently being worked toward (null when final removal is achieved). */
    96|  nextPhase: IndependencePhaseId | null;
    97|  phases: IndependencePhase[];
    98|  keptSystems: KeptSystem[];
    99|  rorkDependenciesRemaining: RorkDependency[];
   100|  /** BLOCK 47 — the prepared, off-Rork executable cutover. */
   101|  cutoverTooling: CutoverTooling;
   102|  /** The six final-phase owner capabilities, derived from the handoff manifest + tools. */
   103|  ownerCapabilities: PhaseRequirement[];
   104|  summary: {
   105|    phasesAchieved: number;
   106|    rorkRequiredForNormalWorkflow: boolean;
   107|    rorkOptional: boolean;
   108|    canReceiveOwnerCommands: boolean;
   109|    canModifyCode: boolean;
   110|    canDeploy: boolean;
   111|    canVerifyProduction: boolean;
   112|    canStoreProof: boolean;
   113|    canLearnFromOutcomes: boolean;
   114|  };
   115|  nextActions: string[];
   116|};
   117|
   118|type EnvSnapshot = Record<string, string | undefined>;
   119|
   120|function present(env: EnvSnapshot, name: string): boolean {
   121|  const value = env[name];
   122|  return typeof value === 'string' && value.trim().length > 0;
   123|}
   124|
   125|/** True when a named tool from the availability checker is available. */
   126|function toolUp(tools: ToolAvailabilityReport, id: string): boolean {
   127|  return tools.tools.find((t) => t.tool === id)?.available ?? false;
   128|}
   129|
   130|async function fileExists(relPath: string): Promise<boolean> {
   131|  try {
   132|    await readFile(path.join(process.cwd(), relPath), 'utf8');
   133|    return true;
   134|  } catch {
   135|    return false;
   136|  }
   137|}
   138|
   139|/** Read a JSON file relative to the repo root; null on any failure. */
   140|async function readJsonFile(relPath: string): Promise<Record<string, unknown> | null> {
   141|  try {
   142|    const raw = await readFile(path.join(process.cwd(), relPath), 'utf8');
   143|    return JSON.parse(raw) as Record<string, unknown>;
   144|  } catch {
   145|    return null;
   146|  }
   147|}
   148|
   149|/** Detect the BLOCK 47 executable cutover artifacts prepared in the repo. */
   150|async function detectCutoverTooling(): Promise<CutoverTooling> {
   151|  const cutoverScript = 'expo/scripts/rork-independence-cutover.mjs';
   152|  const standaloneMetroConfig = 'expo/metro.config.independent.js';
   153|  const ownerBuildPipeline = 'deploy/ci/ivx-independent-build.yml';
   154|  const [scriptPresent, metroPresent, pipelinePresent] = await Promise.all([
   155|    fileExists(cutoverScript),
   156|    fileExists(standaloneMetroConfig),
   157|    fileExists(ownerBuildPipeline),
   158|  ]);
   159|  const ready = scriptPresent && metroPresent && pipelinePresent;
   160|  return {
   161|    ready,
   162|    cutoverScript,
   163|    cutoverScriptPresent: scriptPresent,
   164|    standaloneMetroConfig,
   165|    standaloneMetroConfigPresent: metroPresent,
   166|    ownerBuildPipeline,
   167|    ownerBuildPipelinePresent: pipelinePresent,
   168|    runCommand: 'IVX_ALLOW_RORK_CUTOVER=1 node expo/scripts/rork-independence-cutover.mjs',
   169|    detail: ready
   170|      ? 'Executable build-independence cutover is prepared. Run it on the independent GitHub/Render checkout (off Rork) to remove @rork-ai/toolkit-sdk + withRorkMetro + rork.json in one pass; it is guarded so it cannot brick the Rork-managed preview.'
   171|      : 'Cutover tooling is incomplete — one or more of the cutover script / standalone Metro config / owner build pipeline is missing.',
   172|  };
   173|}
   174|
   175|/** Detect the Rork-specific dependencies still present in repo/runtime. */
   176|async function detectRorkDependencies(env: EnvSnapshot): Promise<RorkDependency[]> {
   177|  const expoPkg = await readJsonFile('expo/package.json');
   178|  const deps = (expoPkg?.dependencies ?? {}) as Record<string, unknown>;
   179|  const rorkSdkInstalled = Object.prototype.hasOwnProperty.call(deps, '@rork-ai/toolkit-sdk');
   180|
   181|  const rorkPublicEnvKeys = Object.keys(env).filter(
   182|    (k) => /^EXPO_PUBLIC_RORK_/.test(k) || k === 'EXPO_PUBLIC_TOOLKIT_URL',
   183|  );
   184|  const rorkPublicEnvsPresent = rorkPublicEnvKeys.length > 0;
   185|
   186|  const rorkConfigPresent = await fileExists('rork.json');
   187|  const rorkIgnorePresent = await fileExists('.rorkignore');
   188|
   189|  return [
   190|    {
   191|      dependency: '@rork-ai/toolkit-sdk (expo/package.json)',
   192|      present: rorkSdkInstalled,
   193|      risk: 'high',
   194|      detail: rorkSdkInstalled
   195|        ? 'Rork toolkit SDK is still declared in expo/package.json — a fresh install re-introduces the Rork client into the bundle.'
   196|        : 'Rork toolkit SDK is no longer declared in expo/package.json.',
   197|      removalAction: 'Run `bun remove @rork-ai/toolkit-sdk` in expo/ and commit package.json + bun.lock.',
   198|    },
   199|    {
   200|      dependency: 'EXPO_PUBLIC_RORK_* / EXPO_PUBLIC_TOOLKIT_URL runtime envs',
   201|      present: rorkPublicEnvsPresent,
   202|      risk: 'high',
   203|      detail: rorkPublicEnvsPresent
   204|        ? `Rork-prefixed public envs still configured: ${rorkPublicEnvKeys.join(', ')}.`
   205|        : 'No Rork-prefixed public envs detected in this runtime.',
   206|      removalAction: 'Delete the EXPO_PUBLIC_RORK_* + EXPO_PUBLIC_TOOLKIT_URL variables from the Render/Expo env panels and rotate RORK_TOOLKIT_SECRET_KEY.',
   207|    },
   208|    {
   209|      dependency: 'rork.json project config',
   210|      present: rorkConfigPresent,
   211|      risk: 'low',
   212|      detail: rorkConfigPresent
   213|        ? 'rork.json is still present (config-only; harmless until full cut-over).'
   214|        : 'rork.json has been removed.',
   215|      removalAction: 'Delete rork.json once development no longer runs inside the Rork sandbox.',
   216|    },
   217|    {
   218|      dependency: '.rorkignore',
   219|      present: rorkIgnorePresent,
   220|      risk: 'low',
   221|      detail: rorkIgnorePresent
   222|        ? '.rorkignore is still present (sandbox-only; cosmetic).'
   223|        : '.rorkignore has been removed.',
   224|      removalAction: 'Delete .rorkignore on the IVX-owned branch after cut-over.',
   225|    },
   226|  ];
   227|}
   228|
   229|function buildKeptSystems(tools: ToolAvailabilityReport): KeptSystem[] {
   230|  return [
   231|    {
   232|      system: 'GitHub',
   233|      available: toolUp(tools, 'github_write'),
   234|      backedBy: 'ivx-developer-deploy-control (Git/Refs API)',
   235|      missing: toolUp(tools, 'github_write') ? null : 'GITHUB_TOKEN / GITHUB_REPO_URL',
   236|    },
   237|    {
   238|      system: 'Render',
   239|      available: toolUp(tools, 'render_deploy'),
   240|      backedBy: 'render.yaml auto-deploy + ivx-production-guard',
   241|      missing: toolUp(tools, 'render_deploy') ? null : 'RENDER_API_KEY / RENDER_SERVICE_ID (push-to-main still deploys without them)',
   242|    },
   243|    {
   244|      system: 'Supabase',
   245|      available: toolUp(tools, 'supabase_actions'),
   246|      backedBy: 'ivx-supabase-owner-actions (ivx_exec_sql RPC + PostgREST)',
   247|      missing: toolUp(tools, 'supabase_actions') ? null : 'SUPABASE_SERVICE_ROLE_KEY / EXPO_PUBLIC_SUPABASE_URL',
   248|    },
   249|    {
   250|      system: 'OpenAI / AI provider',
   251|      available: toolUp(tools, 'ai_gateway'),
   252|      backedBy: 'AI gateway (openai/gpt-4o-mini)',
   253|      missing: toolUp(tools, 'ai_gateway') ? null : 'AI_GATEWAY_API_KEY',
   254|    },
   255|    {
   256|      system: 'IVX backend',
   257|      available: true,
   258|      backedBy: 'Hono API on Render (api.ivxholding.com)',
   259|      missing: null,
   260|    },
   261|    {
   262|      system: 'IVX memory',
   263|      available: true,
   264|      backedBy: 'ivx-unified-memory-store (durable, on-disk)',
   265|      missing: null,
   266|    },
   267|    {
   268|      system: 'IVX scheduler',
   269|      available: true,
   270|      backedBy: 'ivx-autonomous-scheduler (restart-safe)',
   271|      missing: null,
   272|    },
   273|    {
   274|      system: 'IVX action loop',
   275|      available: true,
   276|      backedBy: 'ivx-executive-action-loop (recommend → execute → outcome → learn)',
   277|      missing: null,
   278|    },
   279|  ];
   280|}
   281|
   282|function req(label: string, met: boolean, detailMet: string, detailUnmet: string, missing: string | null): PhaseRequirement {
   283|  return { label, met, detail: met ? detailMet : detailUnmet, missing: met ? null : missing };
   284|}
   285|
   286|/** Resolve a phase readiness: achieved when all reqs met; blocked when the prior phase is not achieved; else in_progress. */
   287|function resolveReadiness(requirements: PhaseRequirement[], priorAchieved: boolean): PhaseReadiness {
   288|  const allMet = requirements.every((r) => r.met);
   289|  if (allMet) return 'achieved';
   290|  if (!priorAchieved) return 'blocked';
   291|  return 'in_progress';
   292|}
   293|
   294|/** Inputs the pure assembler needs — gathered by `buildRorkIndependenceReport`, injectable in tests. */
   295|export type RorkIndependenceInputs = {
   296|  tools: ToolAvailabilityReport;
   297|  manifest: HandoffManifest | null;
   298|  rorkDeps: RorkDependency[];
   299|  /** BLOCK 47 — optional; defaults to a not-ready cutover when omitted (e.g. older tests). */
   300|  cutover?: CutoverTooling;
   301|};
   302|
   303|/**
   304| * Build the live Rork-independence report from real signals.
   305| * Read-only; never mutates anything; never throws (degrades to honest unmet).
   306| */
   307|export async function buildRorkIndependenceReport(
   308|  env: EnvSnapshot = process.env,
   309|): Promise<RorkIndependenceReport> {
   310|  const tools = checkToolAvailability(env);
   311|
   312|  let manifest: HandoffManifest | null = null;
   313|  try {
   314|    const { buildHandoffManifest } = await import('./ivx-handoff');
   315|    manifest = await buildHandoffManifest();
   316|  } catch {
   317|    manifest = null;
   318|  }
   319|
   320|  const rorkDeps = await detectRorkDependencies(env);
   321|  const cutover = await detectCutoverTooling();
   322|  return assembleRorkIndependenceReport({ tools, manifest, rorkDeps, cutover });
   323|}
   324|
   325|/**
   326| * Pure assembler: derive the 4-phase report from already-gathered signals.
   327| * Deterministic + side-effect-free, so it is fully unit-testable.
   328| */
   329|export function assembleRorkIndependenceReport(inputs: RorkIndependenceInputs): RorkIndependenceReport {
   330|  const { tools, manifest, rorkDeps } = inputs;
   331|  const cutoverTooling: CutoverTooling = inputs.cutover ?? {
   332|    ready: false,
   333|    cutoverScript: 'expo/scripts/rork-independence-cutover.mjs',
   334|    cutoverScriptPresent: false,
   335|    standaloneMetroConfig: 'expo/metro.config.independent.js',
   336|    standaloneMetroConfigPresent: false,
   337|    ownerBuildPipeline: 'deploy/ci/ivx-independent-build.yml',
   338|    ownerBuildPipelinePresent: false,
   339|    runCommand: 'IVX_ALLOW_RORK_CUTOVER=1 node expo/scripts/rork-independence-cutover.mjs',
   340|    detail: 'Cutover tooling state not provided.',
   341|  };
   342|  const keptSystems = buildKeptSystems(tools);
   343|
   344|  const coreLifecycleReady =
   345|    toolUp(tools, 'ai_gateway') && toolUp(tools, 'test_runner') &&
   346|    toolUp(tools, 'self_heal') && toolUp(tools, 'execution_trace');
   347|  const deployPathReady = toolUp(tools, 'github_write') || toolUp(tools, 'render_deploy');
   348|  const proofReady = toolUp(tools, 'execution_trace');
   349|
   350|  const handoffBlocked = manifest ? manifest.summary.blocked : 0;
   351|  const handoffReady = manifest ? manifest.handoffReady : false;
   352|
   353|  const sdkPresent = rorkDeps.find((d) => d.dependency.startsWith('@rork-ai'))?.present ?? true;
   354|  const rorkEnvsPresent = rorkDeps.find((d) => d.dependency.startsWith('EXPO_PUBLIC_RORK'))?.present ?? true;
   355|  const rorkConfigPresent = rorkDeps.find((d) => d.dependency.startsWith('rork.json'))?.present ?? true;
   356|
   357|  const keptAllAvailable = keptSystems.every((k) => k.available);
   358|  const keptMissing = keptSystems.filter((k) => !k.available).map((k) => k.system);
   359|
   360|  // ---- Phase 1 — Shadow Mode ----
   361|  const phase1Reqs: PhaseRequirement[] = [
   362|    req(
   363|      'IVX runs the full lifecycle end-to-end',
   364|      tools.canExecuteEndToEnd,
   365|      'Autonomous Mode can inspect → plan → execute → test → deploy → verify → report (canExecuteEndToEnd=true).',
   366|      'The autonomous lifecycle is not end-to-end capable.',
   367|      tools.blockedSteps.length > 0 ? `blocked steps: ${tools.blockedSteps.join(', ')}` : 'core tool or deploy path missing',
   368|    ),
   369|    req(
   370|      'Test + self-heal + proof tools online',
   371|      coreLifecycleReady && proofReady,
   372|      'Test runner, self-heal cycle, and the execution-trace/evidence store are all online.',
   373|      'One of the test/self-heal/proof tools is unavailable.',
   374|      'test_runner / self_heal / execution_trace',
   375|    ),
   376|    req(
   377|      'A deploy path is available',
   378|      deployPathReady,
   379|      'Direct GitHub/Render control or push-to-main auto-deploy is available.',
   380|      'No deploy path is available.',
   381|      'GITHUB_TOKEN/GITHUB_REPO_URL or RENDER_API_KEY/RENDER_SERVICE_ID',
   382|    ),
   383|  ];
   384|  const phase1: IndependencePhase = {
   385|    id: 'shadow',
   386|    order: 1,
   387|    title: 'Shadow Mode',
   388|    objective: 'IVX performs the same tasks as Rork (inspect/plan/edit/test/deploy/verify/report); Rork only audits IVX.',
   389|    rorkRole: 'Auditor — Rork reviews IVX output but no longer drives the work.',
   390|    requirements: phase1Reqs,
   391|    readiness: resolveReadiness(phase1Reqs, true),
   392|  };
   393|
   394|  // ---- Phase 2 — IVX Primary Mode ----
   395|  const phase2Reqs: PhaseRequirement[] = [
   396|    req(
   397|      'AI reasoning gateway online',
   398|      toolUp(tools, 'ai_gateway'),
   399|      'AI gateway present — IVX reasons, plans, and synthesizes directly.',
   400|      'AI gateway key missing — reasoning falls back to deterministic routing only.',
   401|      'AI_GATEWAY_API_KEY',
   402|    ),
   403|    req(
   404|      'Self-driving scheduler + action loop wired',
   405|      true,
   406|      'Autonomous scheduler (daily self-audit + drift) and the executive action loop run in-process.',
   407|      '',
   408|      null,
   409|    ),
   410|    req(
   411|      'Operator handoff has no blocked capability',
   412|      handoffBlocked === 0,
   413|      'All 10 operator capabilities are ready or partial (none blocked).',
   414|      `${handoffBlocked} operator capability(ies) are blocked.`,
   415|      manifest ? manifest.ownerActionsRequired.join('; ') : 'handoff manifest unavailable',
   416|    ),
   417|  ];
   418|  const phase2: IndependencePhase = {
   419|    id: 'ivx_primary',
   420|    order: 2,
   421|    title: 'IVX Primary Mode',
   422|    objective: 'IVX executes tasks directly. Rork is used only as a fallback.',
   423|    rorkRole: 'Fallback only — invoked when IVX cannot complete a task itself.',
   424|    requirements: phase2Reqs,
   425|    readiness: resolveReadiness(phase2Reqs, phase1.readiness === 'achieved'),
   426|  };
   427|
   428|  // ---- Phase 3 — Independence Mode ----
   429|  const phase3Reqs: PhaseRequirement[] = [
   430|    req(
   431|      'All eight kept systems available',
   432|      keptAllAvailable,
   433|      'GitHub, Render, Supabase, OpenAI/provider, IVX backend, memory, scheduler, and action loop are all available.',
   434|      `Kept system(s) unavailable: ${keptMissing.join(', ')}.`,
   435|      keptMissing.length > 0 ? keptMissing.join(', ') : null,
   436|    ),
   437|    req(
   438|      'Rork toolkit SDK removed from the bundle',
   439|      !sdkPresent,
   440|      'The Rork toolkit SDK is no longer a dependency.',
   441|      'The Rork toolkit SDK is still declared in expo/package.json.',
   442|      'remove @rork-ai/toolkit-sdk from expo/package.json',
   443|    ),
   444|    req(
   445|      'Rork-prefixed runtime envs removed',
   446|      !rorkEnvsPresent,
   447|      'No Rork-prefixed public envs remain in the runtime.',
   448|      'Rork-prefixed public envs are still configured in this runtime.',
   449|      'delete EXPO_PUBLIC_RORK_* / EXPO_PUBLIC_TOOLKIT_URL',
   450|    ),
   451|  ];
   452|  const phase3: IndependencePhase = {
   453|    id: 'independence',
   454|    order: 3,
   455|    title: 'Independence Mode',
   456|    objective: 'Remove Rork from the normal workflow. Keep only GitHub, Render, Supabase, OpenAI/provider, IVX backend, IVX memory, IVX scheduler, IVX action loop.',
   457|    rorkRole: 'Out of the normal workflow — code edits/deploys flow through GitHub + Render + IVX.',
   458|    requirements: phase3Reqs,
   459|    readiness: resolveReadiness(phase3Reqs, phase2.readiness === 'achieved'),
   460|  };
   461|
   462|  // ---- Phase 4 — Final Removal ----
   463|  const phase4Reqs: PhaseRequirement[] = [
   464|    req(
   465|      'Rork config files removed',
   466|      !rorkConfigPresent,
   467|      'rork.json has been removed from the IVX-owned branch.',
   468|      'rork.json is still present (config-only; remove on cut-over).',
   469|      'delete rork.json',
   470|    ),
   471|    req(
   472|      'All owner-required capabilities proven',
   473|      handoffReady,
   474|      'Receive commands, modify code, push/deploy, verify production, store proof, and learn from outcomes are all proven.',
   475|      'One or more owner-required capabilities are not yet proven by the handoff manifest.',
   476|      manifest ? manifest.ownerActionsRequired.join('; ') || 'handoff not ready' : 'handoff manifest unavailable',
   477|    ),
   478|  ];
   479|  const phase4: IndependencePhase = {
   480|    id: 'final_removal',
   481|    order: 4,
   482|    title: 'Final Removal',
   483|    objective: 'Rork becomes optional, not required. IVX can receive owner commands, modify code, push/deploy, verify production, store proof, and learn from outcomes.',
   484|    rorkRole: 'Optional — available as a convenience, never required for normal operation.',
   485|    requirements: phase4Reqs,
   486|    readiness: resolveReadiness(phase4Reqs, phase3.readiness === 'achieved'),
   487|  };
   488|
   489|  const phases = [phase1, phase2, phase3, phase4];
   490|
   491|  // Highest fully-achieved phase IVX is operating at right now.
   492|  let currentPhase: IndependencePhase = phase1;
   493|  let currentPhaseOrder = 0;
   494|  for (const p of phases) {
   495|    if (p.readiness === 'achieved') {
   496|      currentPhase = p;
   497|      currentPhaseOrder = p.order;
   498|    } else {
   499|      break;
   500|    }
   501|  }
   502|  const resolvedCurrent: IndependencePhaseId = currentPhaseOrder === 0 ? 'shadow' : currentPhase.id;
   503|  const nextPhase = phases.find((p) => p.readiness !== 'achieved')?.id ?? null;
   504|
   505|  // Owner-required final capabilities (mapped to real handoff/tool signals).
   506|  const ownerCapabilities: PhaseRequirement[] = [
   507|    req('Receive owner commands', true, 'Owner-gated /api/ivx/owner-ai + autonomous-mode/run accept owner tasks.', '', null),
   508|    req(
   509|      'Modify code',
